class Solution(object):
    def maximumProfit(self, prices, k):
        INF = float('inf')
        dp = [[-INF] * 3 for _ in range(k + 1)]
        dp[0][0] = 0
        for p in prices:
            ndp = [[-INF] * 3 for _ in range(k + 1)]
            for t in range(k + 1):
                if dp[t][0] != -INF:
                    ndp[t][0] = max(ndp[t][0], dp[t][0])
                    ndp[t][1] = max(ndp[t][1], dp[t][0] - p)
                    ndp[t][2] = max(ndp[t][2], dp[t][0] + p)
                if dp[t][1] != -INF:
                    ndp[t][1] = max(ndp[t][1], dp[t][1])
                    if t + 1 <= k:
                        ndp[t + 1][0] = max(ndp[t + 1][0], dp[t][1] + p)
                if dp[t][2] != -INF:
                    ndp[t][2] = max(ndp[t][2], dp[t][2])
                    if t + 1 <= k:
                        ndp[t + 1][0] = max(ndp[t + 1][0], dp[t][2] - p)
            dp = ndp
        return max(dp[t][0] for t in range(k + 1) if dp[t][0] != -INF)
